Scripts.PowerShellCode:
# ============================================================
# Move User to Disabled OU
# ============================================================

Import-Module ActiveDirectory

$Username   = 'jdoe'
$DisabledOU = 'OU=Disabled Users,DC=contoso,DC=com'

try {
    $User = Get-ADUser -Identity $Username
    $CurrentOU = ($User.DistinguishedName -split ',', 2)[1]

    Write-Host "User          : $($User.Name)" -ForegroundColor Cyan
    Write-Host "Current OU    : $CurrentOU" -ForegroundColor Cyan
    Write-Host "Destination OU: $DisabledOU" -ForegroundColor Cyan

    if ($CurrentOU -eq $DisabledOU) {
        Write-Host "[INFO] User is already in the Disabled OU" -ForegroundColor Yellow
    } else {
        Move-ADObject -Identity $User.DistinguishedName -TargetPath $DisabledOU
        Write-Host "[OK] User moved to Disabled OU successfully" -ForegroundColor Green

        # Confirm
        $Moved = Get-ADUser -Identity $Username
        Write-Host "New DN: $($Moved.DistinguishedName)" -ForegroundColor Green
    }
} catch {
    Write-Host "[ERROR] $_" -ForegroundColor Red
}

# ============================================================
# Reset AD User Password
# ============================================================

Import-Module ActiveDirectory

$Username            = 'jdoe'
$NewPassword         = ConvertTo-SecureString 'TempPass@2024!' -AsPlainText -Force
$ForceChangeAtLogon  = $true
$UnlockAccount       = $true

try {
    $User = Get-ADUser -Identity $Username -Properties LockedOut, Enabled
    Write-Host "Resetting password for: $($User.Name) ($Username)" -ForegroundColor Cyan

    # Reset password
    Set-ADAccountPassword -Identity $Username -NewPassword $NewPassword -Reset
    Write-Host "[OK] Password reset successfully" -ForegroundColor Green

    # Force change at next logon
    if ($ForceChangeAtLogon) {
        Set-ADUser -Identity $Username -ChangePasswordAtLogon $true
        Write-Host "[OK] User must change password at next logon" -ForegroundColor Green
    }

    # Unlock if locked
    if ($UnlockAccount -and $User.LockedOut) {
        Unlock-ADAccount -Identity $Username
        Write-Host "[OK] Account unlocked" -ForegroundColor Green
    }

    # Ensure account is enabled
    if (-not $User.Enabled) {
        Write-Host "[WARN] Account is currently DISABLED" -ForegroundColor Yellow
    }

    Write-Host "`n[DONE] Password reset complete for '$Username'" -ForegroundColor Green

} catch {
    Write-Host "[ERROR] $_" -ForegroundColor Red
}

# ============================================================
# Unlock AD User Account
# ============================================================

Import-Module ActiveDirectory

$Username = 'jdoe'

try {
    $User = Get-ADUser -Identity $Username -Properties LockedOut, BadLogonCount, LastBadPasswordAttempt, BadPwdCount

    Write-Host "Account Info for: $($User.Name)" -ForegroundColor Cyan
    Write-Host "  Locked Out         : $($User.LockedOut)"
    Write-Host "  Bad Logon Count    : $($User.BadLogonCount)"
    Write-Host "  Last Bad Password  : $($User.LastBadPasswordAttempt)"

    if ($User.LockedOut) {
        Unlock-ADAccount -Identity $Username
        Write-Host "`n[OK] Account '$Username' has been unlocked" -ForegroundColor Green
    } else {
        Write-Host "`n[INFO] Account '$Username' is NOT locked out" -ForegroundColor Yellow
    }

    # Final status
    $Updated = Get-ADUser -Identity $Username -Properties LockedOut, Enabled
    Write-Host "`nCurrent Status:" -ForegroundColor Yellow
    Write-Host "  Locked  : $($Updated.LockedOut)"
    Write-Host "  Enabled : $($Updated.Enabled)"

} catch {
    Write-Host "[ERROR] $_" -ForegroundColor Red
}

# ============================================================
# Force Password Change at Next Logon
# ============================================================

Import-Module ActiveDirectory

# Single user - set to $null to process list
$SingleUser = 'jdoe'

# Or process a list
$UserList = @('jdoe', 'bsmith', 'ataylor')

$UsersToProcess = if ($SingleUser) { @($SingleUser) } else { $UserList }

Write-Host "Processing $($UsersToProcess.Count) user(s)..." -ForegroundColor Cyan

foreach ($Username in $UsersToProcess) {
    try {
        $User = Get-ADUser -Identity $Username -Properties PasswordLastSet, ChangePasswordAtLogon
        Set-ADUser -Identity $Username -ChangePasswordAtLogon $true

        Write-Host "[OK] $Username - Password change forced at next logon" -ForegroundColor Green
        Write-Host "     Last Password Set: $($User.PasswordLastSet)"
    } catch {
        Write-Host "[ERROR] $Username - $_" -ForegroundColor Red
    }
}

Write-Host "`n[DONE] Processed $($UsersToProcess.Count) account(s)" -ForegroundColor Green

# ============================================================
# Add AD User to Groups
# ============================================================

Import-Module ActiveDirectory

$Username = 'jdoe'
$Groups   = @(
    'GRP-IT-Staff',
    'GRP-VPN-Users',
    'GRP-SharePoint-Contributors',
    'GRP-Teams-AllStaff'
)

Write-Host "Adding '$Username' to $($Groups.Count) group(s)..." -ForegroundColor Cyan

$Success = 0
$Errors  = 0

foreach ($Group in $Groups) {
    try {
        # Check if already a member
        $Members = Get-ADGroupMember -Identity $Group -Recursive | Where-Object SamAccountName -eq $Username
        if ($Members) {
            Write-Host "  [SKIP] Already member of: $Group" -ForegroundColor Yellow
        } else {
            Add-ADGroupMember -Identity $Group -Members $Username
            Write-Host "  [OK] Added to: $Group" -ForegroundColor Green
            $Success++
        }
    } catch {
        Write-Host "  [ERROR] $Group - $_" -ForegroundColor Red
        $Errors++
    }
}

Write-Host "`nSummary: Added=$Success | Errors=$Errors" -ForegroundColor Yellow

# Show current group memberships
Write-Host "`nCurrent Group Memberships for '$Username':" -ForegroundColor Cyan
(Get-ADUser $Username -Properties MemberOf).MemberOf | ForEach-Object {
    $GroupName = ($_ -split ',')[0] -replace 'CN=',''
    Write-Host "  - $GroupName"
}

# ============================================================
# Remove AD User from Groups
# ============================================================

Import-Module ActiveDirectory

$Username       = 'jdoe'
$RemoveFromAll  = $false   # Set to $true to remove from ALL groups (offboarding)
$SpecificGroups = @(
    'GRP-VPN-Users',
    'GRP-SharePoint-Contributors'
)

Write-Host "Processing group removal for: $Username" -ForegroundColor Cyan

try {
    $User   = Get-ADUser $Username -Properties MemberOf
    $Groups = if ($RemoveFromAll) { $User.MemberOf } else {
        $User.MemberOf | Where-Object { 
            $GroupCN = ($_ -split ',')[0] -replace 'CN=',''
            $SpecificGroups -contains $GroupCN
        }
    }

    Write-Host "Removing from $($Groups.Count) group(s)..." -ForegroundColor Cyan

    foreach ($Group in $Groups) {
        $GroupName = ($Group -split ',')[0] -replace 'CN=',''
        try {
            Remove-ADGroupMember -Identity $Group -Members $Username -Confirm:$false
            Write-Host "  [OK] Removed from: $GroupName" -ForegroundColor Green
        } catch {
            Write-Host "  [ERROR] $GroupName - $_" -ForegroundColor Red
        }
    }

    # Show remaining memberships
    $Remaining = (Get-ADUser $Username -Properties MemberOf).MemberOf
    Write-Host "`nRemaining memberships: $($Remaining.Count)" -ForegroundColor Yellow

} catch {
    Write-Host "[ERROR] $_" -ForegroundColor Red
}

# ============================================================
# Export AD Group Membership
# ============================================================

Import-Module ActiveDirectory

$GroupName  = 'GRP-IT-Staff'   # Leave empty to export ALL groups
$OutputPath = "C:\Reports\GroupMembership_$(Get-Date -f 'yyyyMMdd_HHmmss').csv"
$Recursive  = $true

$Results = @()

if ($GroupName) {
    $Groups = @(Get-ADGroup -Identity $GroupName)
} else {
    $Groups = Get-ADGroup -Filter *
    Write-Host "Exporting all $($Groups.Count) groups..." -ForegroundColor Cyan
}

foreach ($Group in $Groups) {
    try {
        $Members = if ($Recursive) {
            Get-ADGroupMember -Identity $Group.Name -Recursive
        } else {
            Get-ADGroupMember -Identity $Group.Name
        }

        if ($Members.Count -eq 0) {
            $Results += [PSCustomObject]@{
                GroupName    = $Group.Name
                GroupDN      = $Group.DistinguishedName
                MemberName   = '<Empty Group>'
                MemberSAM    = ''
                MemberType   = ''
            }
        } else {
            foreach ($Member in $Members) {
                $Results += [PSCustomObject]@{
                    GroupName  = $Group.Name
                    GroupDN    = $Group.DistinguishedName
                    MemberName = $Member.Name
                    MemberSAM  = $Member.SamAccountName
                    MemberType = $Member.objectClass
                }
            }
        }
        Write-Host "[OK] $($Group.Name) - $($Members.Count) members" -ForegroundColor Green
    } catch {
        Write-Host "[ERROR] $($Group.Name) - $_" -ForegroundColor Red
    }
}

$Results | Export-Csv $OutputPath -NoTypeInformation
Write-Host "`n[DONE] Exported to: $OutputPath" -ForegroundColor Green

# ============================================================
# Password Expiration Report
# ============================================================

Import-Module ActiveDirectory

$DaysUntilExpiry = 14    # Warn for passwords expiring within 14 days
$SearchBase      = 'DC=contoso,DC=com'
$OutputPath      = "C:\Reports\PwdExpiring_$(Get-Date -f 'yyyyMMdd').csv"
$MaxPasswordAge  = (Get-ADDefaultDomainPasswordPolicy).MaxPasswordAge.Days

Write-Host "Max password age: $MaxPasswordAge days" -ForegroundColor Cyan
Write-Host "Warning window  : $DaysUntilExpiry days" -ForegroundColor Cyan

$Users = Get-ADUser -Filter {
    Enabled -eq $true -and
    PasswordNeverExpires -eq $false -and
    PasswordExpired -eq $false
} -SearchBase $SearchBase `
   -Properties PasswordLastSet, EmailAddress, Department, Title, PasswordNeverExpires, PasswordExpired

$Report = @()
foreach ($User in $Users) {
    if ($User.PasswordLastSet) {
        $ExpiryDate  = $User.PasswordLastSet.AddDays($MaxPasswordAge)
        $DaysLeft    = (New-TimeSpan -Start (Get-Date) -End $ExpiryDate).Days

        if ($DaysLeft -le $DaysUntilExpiry -and $DaysLeft -ge 0) {
            $Report += [PSCustomObject]@{
                Username       = $User.SamAccountName
                DisplayName    = $User.DisplayName
                Email          = $User.EmailAddress
                Department     = $User.Department
                PasswordLastSet = $User.PasswordLastSet
                ExpiryDate     = $ExpiryDate
                DaysUntilExpiry = $DaysLeft
            }
        }
    }
}

$Report = $Report | Sort-Object DaysUntilExpiry
$Report | Export-Csv $OutputPath -NoTypeInformation

Write-Host "`nPasswords expiring within $DaysUntilExpiry days: $($Report.Count)" -ForegroundColor Yellow
$Report | ForEach-Object {
    $Color = if ($_.DaysUntilExpiry -le 3) { 'Red' } elseif ($_.DaysUntilExpiry -le 7) { 'Yellow' } else { 'Cyan' }
    Write-Host "  $($_.Username) - Expires in $($_.DaysUntilExpiry) days ($($_.ExpiryDate.ToString('yyyy-MM-dd')))" -ForegroundColor $Color
}
Write-Host "`nReport saved: $OutputPath" -ForegroundColor Green

# ============================================================
# Users with No Logon in X Days
# ============================================================

Import-Module ActiveDirectory

$Days       = 60
$SearchBase = 'DC=contoso,DC=com'
$OutputPath = "C:\Reports\NoLogon${Days}Days_$(Get-Date -f 'yyyyMMdd').csv"
$Cutoff     = (Get-Date).AddDays(-$Days)

$Users = Get-ADUser -Filter { Enabled -eq $true } -SearchBase $SearchBase `
    -Properties LastLogonDate, Department, Title, WhenCreated |
    Where-Object { $null -eq $_.LastLogonDate -or $_.LastLogonDate -lt $Cutoff }

$Report = $Users | Select-Object @{
    N='Username';   E={ $_.SamAccountName }},
    DisplayName, Department, Title,
    @{N='LastLogon'; E={ if ($_.LastLogonDate) { $_.LastLogonDate } else { 'Never' } }},
    @{N='DaysSince'; E={
        if ($_.LastLogonDate) { [math]::Round((New-TimeSpan $_.LastLogonDate (Get-Date)).TotalDays) }
        else { 'N/A - Never logged on' }
    }},
    @{N='AccountAge_Days'; E={ [math]::Round((New-TimeSpan $_.WhenCreated (Get-Date)).TotalDays) }}

$Report | Export-Csv $OutputPath -NoTypeInformation
Write-Host "Found $($Report.Count) users inactive for $Days+ days" -ForegroundColor Yellow
Write-Host "Report: $OutputPath" -ForegroundColor Green

# ============================================================
# Create Local Windows User
# ============================================================

$ComputerName = $env:COMPUTERNAME   # Or specify remote: 'REMOTE-PC01'
$Username     = 'LocalAdmin'
$FullName     = 'Local Admin Account'
$Description  = 'Local administrative account - IT Managed'
$Password     = ConvertTo-SecureString 'P@ssw0rd123!' -AsPlainText -Force
$AddToGroup   = 'Administrators'   # Or 'Users'

try {
    if ($ComputerName -eq $env:COMPUTERNAME) {
        # Local machine
        New-LocalUser `
            -Name        $Username `
            -FullName    $FullName `
            -Description $Description `
            -Password    $Password `
            -PasswordNeverExpires:$true `
            -UserMayNotChangePassword:$false

        Add-LocalGroupMember -Group $AddToGroup -Member $Username
        Write-Host "[OK] Local user '$Username' created and added to '$AddToGroup'" -ForegroundColor Green
    } else {
        # Remote machine via Invoke-Command
        Invoke-Command -ComputerName $ComputerName -ScriptBlock {
            param($u, $fn, $desc, $pwd, $grp)
            New-LocalUser -Name $u -FullName $fn -Description $desc -Password $pwd -PasswordNeverExpires:$true
            Add-LocalGroupMember -Group $grp -Member $u
        } -ArgumentList $Username, $FullName, $Description, $Password, $AddToGroup
        Write-Host "[OK] Local user '$Username' created on '$ComputerName'" -ForegroundColor Green
    }
} catch {
    Write-Host "[ERROR] $_" -ForegroundColor Red
}

# ============================================================
# Manage Windows Services
# ============================================================

$Computers   = @($env:COMPUTERNAME)  # Add more: @('PC01','PC02','SERVER01')
$ServiceName = 'Spooler'             # Windows Print Spooler
$Action      = 'Restart'             # Start | Stop | Restart

foreach ($Computer in $Computers) {
    Write-Host "[$Computer] Processing service '$ServiceName'..." -ForegroundColor Cyan
    try {
        $Service = Get-Service -Name $ServiceName -ComputerName $Computer -ErrorAction Stop
        Write-Host "  Current Status: $($Service.Status)"

        switch ($Action) {
            'Start'   {
                if ($Service.Status -ne 'Running') { Start-Service -InputObject $Service }
                else { Write-Host "  Already running" -ForegroundColor Yellow }
            }
            'Stop'    {
                if ($Service.Status -ne 'Stopped') { Stop-Service -InputObject $Service -Force }
                else { Write-Host "  Already stopped" -ForegroundColor Yellow }
            }
            'Restart' {
                Restart-Service -InputObject $Service -Force
            }
        }

        Start-Sleep -Seconds 2
        $Updated = Get-Service -Name $ServiceName -ComputerName $Computer
        Write-Host "  New Status: $($Updated.Status)" -ForegroundColor Green

    } catch {
        Write-Host "  [ERROR] $_" -ForegroundColor Red
    }
}

# ============================================================
# Software Inventory Report
# ============================================================

$Computers  = @($env:COMPUTERNAME)
$OutputPath = "C:\Reports\SoftwareInventory_$(Get-Date -f 'yyyyMMdd').csv"
$Results    = @()

$RegPaths = @(
    'HKLM:\Software\Microsoft\Windows\CurrentVersion\Uninstall\*',
    'HKLM:\Software\Wow6432Node\Microsoft\Windows\CurrentVersion\Uninstall\*',
    'HKCU:\Software\Microsoft\Windows\CurrentVersion\Uninstall\*'
)

foreach ($Computer in $Computers) {
    Write-Host "Scanning: $Computer" -ForegroundColor Cyan
    try {
        $Software = if ($Computer -eq $env:COMPUTERNAME) {
            $RegPaths | ForEach-Object { Get-ItemProperty $_ -ErrorAction SilentlyContinue }
        } else {
            Invoke-Command -ComputerName $Computer -ScriptBlock {
                param($paths)
                $paths | ForEach-Object { Get-ItemProperty $_ -ErrorAction SilentlyContinue }
            } -ArgumentList (,$RegPaths)
        }

        $Software | Where-Object { $_.DisplayName } | ForEach-Object {
            $Results += [PSCustomObject]@{
                Computer    = $Computer
                Name        = $_.DisplayName
                Version     = $_.DisplayVersion
                Publisher   = $_.Publisher
                InstallDate = $_.InstallDate
                InstallLocation = $_.InstallLocation
                UninstallString = $_.UninstallString
            }
        }
        Write-Host "  Found $($Results.Where({$_.Computer -eq $Computer}).Count) apps" -ForegroundColor Green
    } catch {
        Write-Host "  [ERROR] $Computer - $_" -ForegroundColor Red
    }
}

$Results | Sort-Object Computer, Name | Export-Csv $OutputPath -NoTypeInformation
Write-Host "`n[DONE] $($Results.Count) total entries saved to: $OutputPath" -ForegroundColor Green

# ============================================================
# Pending Reboot Check
# ============================================================

$Computers  = @($env:COMPUTERNAME)
$OutputPath = "C:\Reports\PendingReboot_$(Get-Date -f 'yyyyMMdd').csv"
$Results    = @()

function Test-PendingReboot ($Computer) {
    $PendingReasons = @()

    try {
        $Reg = [Microsoft.Win32.RegistryKey]::OpenRemoteBaseKey('LocalMachine', $Computer)

        # Windows Update
        $WU = $Reg.OpenSubKey('SOFTWARE\Microsoft\Windows\CurrentVersion\WindowsUpdate\Auto Update\RebootRequired')
        if ($WU) { $PendingReasons += 'WindowsUpdate' }

        # CBS (Component Based Servicing)
        $CBS = $Reg.OpenSubKey('SOFTWARE\Microsoft\Windows\CurrentVersion\Component Based Servicing\RebootPending')
        if ($CBS) { $PendingReasons += 'CBS' }

        # Pending File Rename Operations
        $PFRO = $Reg.OpenSubKey('SYSTEM\CurrentControlSet\Control\Session Manager')
        if ($PFRO) {
            $PFROValue = $PFRO.GetValue('PendingFileRenameOperations')
            if ($PFROValue) { $PendingReasons += 'PendingFileRename' }
        }

        # SCCM
        try {
            $SCCM = Invoke-WmiMethod -ComputerName $Computer `
                -Namespace 'ROOT\ccm\ClientSDK' `
                -Class 'CCM_ClientUtilities' `
                -Name 'DetermineIfRebootPending' -ErrorAction Stop
            if ($SCCM.RebootPending -or $SCCM.IsHardRebootPending) { $PendingReasons += 'SCCM' }
        } catch {}

        $Reg.Close()
    } catch {
        $PendingReasons += "ERROR: $_"
    }

    return $PendingReasons
}

foreach ($Computer in $Computers) {
    Write-Host "Checking: $Computer" -ForegroundColor Cyan
    $Reasons = Test-PendingReboot $Computer
    $Pending = $Reasons.Count -gt 0
    $Color   = if ($Pending) { 'Yellow' } else { 'Green' }

    Write-Host "  Pending Reboot: $Pending $(if ($Pending) { "($($Reasons -join ', '))" })" -ForegroundColor $Color

    $Results += [PSCustomObject]@{
        Computer      = $Computer
        PendingReboot = $Pending
        Reasons       = $Reasons -join '; '
        CheckTime     = (Get-Date -f 'yyyy-MM-dd HH:mm:ss')
    }
}

$Results | Export-Csv $OutputPath -NoTypeInformation
Write-Host "`nReport: $OutputPath" -ForegroundColor Green

# ============================================================
# Get Detailed IP Configuration
# ============================================================

$Computers  = @($env:COMPUTERNAME)
$OutputPath = "C:\Reports\IPConfig_$(Get-Date -f 'yyyyMMdd').csv"
$Results    = @()

foreach ($Computer in $Computers) {
    Write-Host "\nIP Configuration for: $Computer" -ForegroundColor Cyan
    Write-Host ('=' * 50)

    try {
        $Adapters = Get-CimInstance -ClassName Win32_NetworkAdapterConfiguration `
            -ComputerName $Computer | Where-Object { $_.IPEnabled }

        foreach ($Adapter in $Adapters) {
            Write-Host "  Adapter  : $($Adapter.Description)" -ForegroundColor Yellow
            Write-Host "  IP Addr  : $(($Adapter.IPAddress | Where-Object { $_ -notlike '*:*' }) -join ', ')"
            Write-Host "  Subnet   : $($Adapter.IPSubnet[0])"
            Write-Host "  Gateway  : $(($Adapter.DefaultIPGateway) -join ', ')"
            Write-Host "  DNS      : $(($Adapter.DNSServerSearchOrder) -join ', ')"
            Write-Host "  MAC      : $($Adapter.MACAddress)"
            Write-Host "  DHCP     : $($Adapter.DHCPEnabled)"
            if ($Adapter.DHCPEnabled) {
                Write-Host "  DHCP Svr : $($Adapter.DHCPServer)"
                Write-Host "  Lease    : $($Adapter.DHCPLeaseExpires)"
            }
            Write-Host ''

            $Results += [PSCustomObject]@{
                Computer    = $Computer
                Adapter     = $Adapter.Description
                IP          = ($Adapter.IPAddress | Where-Object { $_ -notlike '*:*' }) -join '; '
                Subnet      = $Adapter.IPSubnet[0]
                Gateway     = ($Adapter.DefaultIPGateway) -join '; '
                DNS         = ($Adapter.DNSServerSearchOrder) -join '; '
                MAC         = $Adapter.MACAddress
                DHCP        = $Adapter.DHCPEnabled
            }
        }
    } catch {
        Write-Host "  [ERROR] $Computer - $_" -ForegroundColor Red
    }
}

$Results | Export-Csv $OutputPath -NoTypeInformation
Write-Host "Report saved: $OutputPath" -ForegroundColor Green

# ============================================================
# Test Network Connections
# ============================================================

$TargetHosts = @(
    @{Host='8.8.8.8';       Port=53;   Label='Google DNS'},
    @{Host='1.1.1.1';       Port=53;   Label='Cloudflare DNS'},
    @{Host='google.com';    Port=443;  Label='Google HTTPS'},
    @{Host='SERVER01';      Port=445;  Label='File Server SMB'},
    @{Host='DC01';          Port=389;  Label='Domain Controller LDAP'},
    @{Host='MAILSERVER';    Port=443;  Label='Mail Server HTTPS'},
    @{Host='WEBSERVER';     Port=80;   Label='Web Server HTTP'}
)

$OutputPath = "C:\Reports\NetTest_$(Get-Date -f 'yyyyMMdd_HHmm').csv"
$Results    = @()

Write-Host ('{0,-30} {1,-6} {2,-10} {3,-10} {4}' -f 'Target', 'Port', 'Status', 'Latency', 'Label') -ForegroundColor Cyan
Write-Host ('-' * 75)

foreach ($Target in $TargetHosts) {
    try {
        $Test    = Test-NetConnection -ComputerName $Target.Host -Port $Target.Port -WarningAction SilentlyContinue
        $Status  = if ($Test.TcpTestSucceeded) { 'SUCCESS' } else { 'FAILED' }
        $Latency = if ($Test.PingReplyDetails) { "$($Test.PingReplyDetails.RoundtripTime)ms" } else { 'N/A' }
        $Color   = if ($Test.TcpTestSucceeded) { 'Green' } else { 'Red' }

        Write-Host ('{0,-30} {1,-6} {2,-10} {3,-10} {4}' -f $Target.Host, $Target.Port, $Status, $Latency, $Target.Label) -ForegroundColor $Color

        $Results += [PSCustomObject]@{
            Host    = $Target.Host
            Port    = $Target.Port
            Label   = $Target.Label
            Status  = $Status
            Latency = $Latency
            Time    = (Get-Date -f 'HH:mm:ss')
        }
    } catch {
        Write-Host ('{0,-30} {1,-6} ERROR      N/A        {2}' -f $Target.Host, $Target.Port, $Target.Label) -ForegroundColor Red
    }
}

$Results | Export-Csv $OutputPath -NoTypeInformation
$Passed = ($Results | Where-Object Status -eq 'SUCCESS').Count
Write-Host "`nResults: $Passed/$($Results.Count) passed | Report: $OutputPath" -ForegroundColor Yellow

# ============================================================
# Ping Sweep / Network Discovery
# ============================================================

$Subnet     = '192.168.1'   # e.g., '10.0.0' or '172.16.1'
$StartRange = 1
$EndRange   = 254
$Timeout    = 200           # milliseconds
$Threads    = 50            # parallel threads
$OutputPath = "C:\Reports\PingSweep_${Subnet}_$(Get-Date -f 'yyyyMMdd_HHmm').csv"

Write-Host "Scanning $Subnet.$StartRange - $Subnet.$EndRange..." -ForegroundColor Cyan

$Jobs    = @()
$Alive   = @()
$Dead    = @()

$IPs = $StartRange..$EndRange | ForEach-Object { "$Subnet.$_" }

# Parallel ping using runspaces for speed
$RunspacePool = [runspacefactory]::CreateRunspacePool(1, $Threads)
$RunspacePool.Open()

$ScriptBlock = {
    param($IP, $Timeout)
    $Ping   = New-Object System.Net.NetworkInformation.Ping
    $Result = $Ping.Send($IP, $Timeout)
    [PSCustomObject]@{
        IP       = $IP
        Status   = $Result.Status
        Latency  = if ($Result.Status -eq 'Success') { $Result.RoundtripTime } else { $null }
        Hostname = try { [System.Net.Dns]::GetHostEntry($IP).HostName } catch { '' }
    }
}

$Pipelines = foreach ($IP in $IPs) {
    $PowerShell = [powershell]::Create()
    $PowerShell.RunspacePool = $RunspacePool
    [void]$PowerShell.AddScript($ScriptBlock).AddArgument($IP).AddArgument($Timeout)
    @{ PS = $PowerShell; IAS = $PowerShell.BeginInvoke() }
}

Write-Host "Waiting for results..." -ForegroundColor Yellow
$Results = foreach ($Pipeline in $Pipelines) {
    $Pipeline.PS.EndInvoke($Pipeline.IAS)
    $Pipeline.PS.Dispose()
}

$RunspacePool.Close()

$Alive = $Results | Where-Object { $_.Status -eq 'Success' } | Sort-Object { [version]$_.IP }
Write-Host "`nLive Hosts: $($Alive.Count)/$($IPs.Count)" -ForegroundColor Green
$Alive | ForEach-Object {
    Write-Host "  $($_.IP) $(if ($_.Hostname) { "($($_.Hostname))" }) - $($_.Latency)ms" -ForegroundColor Green
}

$Results | Export-Csv $OutputPath -NoTypeInformation
Write-Host "`nFull report: $OutputPath" -ForegroundColor Cyan

# ============================================================
# Export Exchange Online Mailbox Statistics
# ============================================================

Connect-ExchangeOnline -UserPrincipalName 'admin@contoso.com'

$OutputPath  = "C:\Reports\MailboxStats_$(Get-Date -f 'yyyyMMdd').csv"
$TopN        = 0    # Set to 0 for all, or number like 50 for top 50 largest

try {
    Write-Host "Fetching mailbox list..." -ForegroundColor Cyan
    $Mailboxes = Get-ExoMailbox -ResultSize Unlimited -Properties DisplayName, PrimarySmtpAddress, RecipientTypeDetails
    Write-Host "Processing $($Mailboxes.Count) mailboxes..." -ForegroundColor Yellow

    $Results = @()
    $Counter = 0

    foreach ($MB in $Mailboxes) {
        $Counter++
        Write-Progress -Activity "Getting stats" -Status "$Counter of $($Mailboxes.Count): $($MB.PrimarySmtpAddress)" -PercentComplete (($Counter / $Mailboxes.Count) * 100)

        try {
            $Stats = Get-ExoMailboxStatistics -Identity $MB.PrimarySmtpAddress -ErrorAction Stop

            $SizeMB = 0
            if ($Stats.TotalItemSize.Value) {
                $SizeMB = [math]::Round($Stats.TotalItemSize.Value.ToBytes() / 1MB, 2)
            }

            $Results += [PSCustomObject]@{
                DisplayName       = $MB.DisplayName
                Email             = $MB.PrimarySmtpAddress
                Type              = $MB.RecipientTypeDetails
                TotalItems        = $Stats.ItemCount
                SizeMB            = $SizeMB
                SizeGB            = [math]::Round($SizeMB / 1024, 3)
                DeletedItems      = $Stats.DeletedItemCount
                LastLogon         = $Stats.LastLogonTime
                LastInteraction   = $Stats.LastInteractionTime
            }
        } catch {
            Write-Host "  [WARN] Could not get stats for: $($MB.PrimarySmtpAddress)" -ForegroundColor Yellow
        }
    }

    $Sorted = $Results | Sort-Object SizeMB -Descending
    if ($TopN -gt 0) { $Sorted = $Sorted | Select-Object -First $TopN }

    $Sorted | Export-Csv $OutputPath -NoTypeInformation

    $TotalGB = [math]::Round(($Results | Measure-Object SizeMB -Sum).Sum / 1024, 2)
    Write-Host "`n[DONE] Total mailbox storage: ${TotalGB}GB | Report: $OutputPath" -ForegroundColor Green

} catch {
    Write-Host "[ERROR] $_" -ForegroundColor Red
} finally {
    Disconnect-ExchangeOnline -Confirm:$false
}

