# ============================================================
# CPU / Memory / Disk Performance Report
# ============================================================

$Computers  = @($env:COMPUTERNAME)
$OutputPath = "C:\Reports\PerfReport_$(Get-Date -f 'yyyyMMdd_HHmm').csv"
$Results    = @()

foreach ($Computer in $Computers) {
    Write-Host "Checking: $Computer" -ForegroundColor Cyan
    try {
        $Data = Invoke-Command -ComputerName $Computer -ErrorAction Stop -ScriptBlock {
            # CPU
            $CPU = (Get-CimInstance Win32_Processor | Measure-Object -Property LoadPercentage -Average).Average

            # Memory
            $OS    = Get-CimInstance Win32_OperatingSystem
            $TotalMB = [math]::Round($OS.TotalVisibleMemorySize / 1KB)
            $FreeMB  = [math]::Round($OS.FreePhysicalMemory / 1KB)
            $UsedMB  = $TotalMB - $FreeMB
            $MemPct  = [math]::Round(($UsedMB / $TotalMB) * 100, 1)

            # Disks
            $Disks = Get-CimInstance Win32_LogicalDisk -Filter "DriveType=3" | ForEach-Object {
                $TotalGB = [math]::Round($_.Size / 1GB, 1)
                $FreeGB  = [math]::Round($_.FreeSpace / 1GB, 1)
                $UsedPct = [math]::Round((($_.Size - $_.FreeSpace) / $_.Size) * 100, 1)
                "$($_.DeviceID) $UsedPct% ($FreeGB/$TotalGB GB free)"
            }

            [PSCustomObject]@{
                CPU_Pct     = $CPU
                RAM_Total_GB = $TotalMB / 1024
                RAM_Used_GB  = $UsedMB / 1024
                RAM_Pct      = $MemPct
                Disks        = $Disks -join ' | '
            }
        }

        $CpuColor = if ($Data.CPU_Pct -gt 85) { 'Red' } elseif ($Data.CPU_Pct -gt 60) { 'Yellow' } else { 'Green' }
        $RamColor = if ($Data.RAM_Pct -gt 90) { 'Red' } elseif ($Data.RAM_Pct -gt 75) { 'Yellow' } else { 'Green' }

        Write-Host "  CPU : $($Data.CPU_Pct)%" -ForegroundColor $CpuColor
        Write-Host "  RAM : $($Data.RAM_Pct)% ($([math]::Round($Data.RAM_Used_GB,1))GB / $([math]::Round($Data.RAM_Total_GB,1))GB)" -ForegroundColor $RamColor
        Write-Host "  Disk: $($Data.Disks)"

        $Results += [PSCustomObject]@{
            Computer   = $Computer
            CPU_Pct    = $Data.CPU_Pct
            RAM_Pct    = $Data.RAM_Pct
            RAM_UsedGB = [math]::Round($Data.RAM_Used_GB, 2)
            RAM_TotalGB = [math]::Round($Data.RAM_Total_GB, 2)
            Disks      = $Data.Disks
            Timestamp  = (Get-Date -f 'yyyy-MM-dd HH:mm:ss')
        }
    } catch {
        Write-Host "  [ERROR] $_" -ForegroundColor Red
    }
}

$Results | Export-Csv $OutputPath -NoTypeInformation
Write-Host "`nReport saved: $OutputPath" -ForegroundColor Green

