    Write-Host "[$Status] $Step$(if ($Details){' - '+$Details})" -ForegroundColor $Color
    $Script:Report += [PSCustomObject]@{Step=$Step;Status=$Status;Details=$Details;Time=(Get-Date -f 'HH:mm:ss')}
