Import-Module ActiveDirectory

$SearchBase = 'DC=contoso,DC=com'
$OutputPath = "C:\Reports\NestedGroups_$(Get-Date -f 'yyyyMMdd').csv"
$Results    = @()

function Get-NestedMembers ($GroupName, $Depth=0, $ParentGroup='') {
    $Members = Get-ADGroupMember -Identity $GroupName -ErrorAction SilentlyContinue
    foreach ($Member in $Members) {
        $Script:Results += [PSCustomObject]@{
            ParentGroup  = $GroupName
            MemberName   = $Member.Name
            MemberSAM    = $Member.SamAccountName
            MemberType   = $Member.ObjectClass
            NestingDepth = $Depth
            Path         = if ($ParentGroup) { "$ParentGroup > $GroupName" } else { $GroupName }
        }
        if ($Member.ObjectClass -eq 'group' -and $Depth -lt 5) {
            Get-NestedMembers -GroupName $Member.SamAccountName -Depth ($Depth+1) -ParentGroup $GroupName
        }
    }
}

$AllGroups = Get-ADGroup -Filter * -SearchBase $SearchBase
Write-Host "Mapping $($AllGroups.Count) groups..." -ForegroundColor Cyan

foreach ($Group in $AllGroups) {
