# ============================================================
# SCHEDULED SERVER HEALTH CHECK
# ============================================================
# Schedule: Daily at 06:00 AM
# Run As: Domain Service Account with admin rights
# ============================================================

$Config = @{
    Servers       = @('SERVER01', 'SERVER02', 'DC01', $env:COMPUTERNAME)
    AlertEmail    = 'it-alerts@contoso.com'
    FromEmail     = 'monitoring@contoso.com'
    SMTPServer    = 'smtp.contoso.com'
    SMTPPort      = 587
    LogPath       = 'C:\Logs\HealthChecks'
    CriticalCPU   = 90    # Alert if CPU > 90%
    CriticalRAM   = 90    # Alert if RAM > 90%
    CriticalDisk  = 85    # Alert if Disk > 85%
    ServiceCheck  = @('Spooler','W32Time','BITS','wuauserv')
}

$Timestamp  = Get-Date -f 'yyyy-MM-dd_HHmm'
$LogFile    = Join-Path $Config.LogPath "HealthCheck_$Timestamp.log"
$Alerts     = @()
$AllResults = @()

if (-not (Test-Path $Config.LogPath)) { New-Item -ItemType Directory $Config.LogPath | Out-Null }

function Write-Log($Message, $Level='INFO') {
    $Entry = "$(Get-Date -f 'yyyy-MM-dd HH:mm:ss') [$Level] $Message"
    Add-Content $LogFile $Entry
    $Color = switch ($Level) { 'ERROR' {'Red'} 'WARN' {'Yellow'} 'OK' {'Green'} default {'White'} }
    Write-Host $Entry -ForegroundColor $Color
}

Write-Log "=== Health Check Started ==="

foreach ($Server in $Config.Servers) {
    Write-Log "Checking: $Server"
    $ServerResult = @{ Server=$Server; Alerts=@(); Checks=@() }

    try {
        $Data = Invoke-Command -ComputerName $Server -ErrorAction Stop -ScriptBlock {
            param($ServiceList)

            $OS    = Get-CimInstance Win32_OperatingSystem
            $CPU   = (Get-CimInstance Win32_Processor | Measure-Object -Property LoadPercentage -Average).Average
            $TotalMB  = $OS.TotalVisibleMemorySize / 1KB
            $FreeMB   = $OS.FreePhysicalMemory / 1KB
            $RAMPct   = [math]::Round((($TotalMB-$FreeMB)/$TotalMB)*100,1)

            $Disks = Get-CimInstance Win32_LogicalDisk -Filter 'DriveType=3' | ForEach-Object {
                @{
                    Drive   = $_.DeviceID
                    TotalGB = [math]::Round($_.Size/1GB,1)
                    FreeGB  = [math]::Round($_.FreeSpace/1GB,1)
                    UsedPct = [math]::Round((($_.Size-$_.FreeSpace)/$_.Size)*100,1)
                }
            }

            $Services = $ServiceList | ForEach-Object {
                $Svc = Get-Service $_ -ErrorAction SilentlyContinue
                if ($Svc) { @{ Name=$Svc.Name; Status=$Svc.Status.ToString() } }
            }

            $EventErrors = (Get-EventLog -LogName System -EntryType Error -Newest 10 -ErrorAction SilentlyContinue).Count

            @{
                CPU        = $CPU
                RAMPct     = $RAMPct
                Disks      = $Disks
                Services   = $Services
                Uptime     = [math]::Round(((Get-Date)-$OS.LastBootUpTime).TotalDays,1)
                EventErrors = $EventErrors
            }
        } -ArgumentList (,$Config.ServiceCheck)

        # Evaluate results
        $Check_CPU = if ($Data.CPU -gt $Config.CriticalCPU) {
            $Alerts += "[$Server] CRITICAL: CPU at $($Data.CPU)%"
            "CRITICAL ($($Data.CPU)%)"
        } else { "OK ($($Data.CPU)%)" }

        $Check_RAM = if ($Data.RAMPct -gt $Config.CriticalRAM) {
            $Alerts += "[$Server] CRITICAL: RAM at $($Data.RAMPct)%"
            "CRITICAL ($($Data.RAMPct)%)"
        } else { "OK ($($Data.RAMPct)%)" }

        foreach ($Disk in $Data.Disks) {
            if ($Disk.UsedPct -gt $Config.CriticalDisk) {
                $Alerts += "[$Server] WARNING: Drive $($Disk.Drive) is $($Disk.UsedPct)% full ($($Disk.FreeGB)GB free)"
            }
        }

        foreach ($Svc in $Data.Services) {
            if ($Svc.Status -ne 'Running') {
                $Alerts += "[$Server] SERVICE DOWN: $($Svc.Name) is $($Svc.Status)"
            }
        }

        Write-Log "  CPU: $Check_CPU | RAM: $Check_RAM | Uptime: $($Data.Uptime)d" 'OK'

    } catch {
        Write-Log "  UNREACHABLE: $_" 'ERROR'
        $Alerts += "[$Server] UNREACHABLE: $($_.Exception.Message)"
    }
}

Write-Log "=== Health Check Complete | Alerts: $($Alerts.Count) ==="

# Send email if there are alerts
if ($Alerts.Count -gt 0) {
    Write-Log "Sending alert email to $($Config.AlertEmail)..."
    $Body = "Health Check Alerts - $(Get-Date -f 'yyyy-MM-dd HH:mm')`n`n" + ($Alerts -join "`n")
    try {
        Send-MailMessage `
            -To         $Config.AlertEmail `
            -From       $Config.FromEmail `
            -Subject    "[ALERT] Server Health Check - $($Alerts.Count) issue(s) detected" `
            -Body       $Body `
            -SmtpServer $Config.SMTPServer `
            -Port       $Config.SMTPPort `
            -UseSsl
        Write-Log "Alert email sent" 'OK'
    } catch {
        Write-Log "Failed to send email: $_" 'ERROR'
    }
} else {
    Write-Log "All checks passed. No alerts." 'OK'
}

