# Remote Software Deployment
# ============================================================
$Computers       = @('PC01','PC02','PC03')   # Or: Get-Content 'computers.txt'
$InstallerPath   = '\\FILESERVER\Software\App\installer.msi'   # UNC path accessible from targets
$InstallerArgs   = '/qn /norestart ALLUSERS=1'
$InstallerType   = 'MSI'   # MSI or EXE
$AppName         = 'MyApplication 2.0'
$OutputPath      = "C:\Logs\Deploy_$(Get-Date -f 'yyyyMMdd_HHmm').csv"
$Results         = @()

Write-Host "Deploying '$AppName' to $($Computers.Count) computers..." -ForegroundColor Cyan

foreach ($Computer in $Computers) {
    Write-Host "  Deploying to: $Computer" -ForegroundColor Yellow
    try {
        $Result = Invoke-Command -ComputerName $Computer -ErrorAction Stop -ScriptBlock {
            param($Path, $Args, $Type, $Name)

            # Check if already installed
            $Installed = Get-ItemProperty `
                'HKLM:\Software\Microsoft\Windows\CurrentVersion\Uninstall\*',
                'HKLM:\Software\Wow6432Node\Microsoft\Windows\CurrentVersion\Uninstall\*' `
                -ErrorAction SilentlyContinue | Where-Object DisplayName -like "*$Name*"

            if ($Installed) {
                return @{ Status='ALREADY_INSTALLED'; ExitCode=0; Message='Already installed' }
            }

            $ExitCode = if ($Type -eq 'MSI') {
                (Start-Process msiexec -ArgumentList "/i `"$Path`" $Args" -Wait -PassThru).ExitCode
            } else {
                (Start-Process $Path -ArgumentList $Args -Wait -PassThru).ExitCode
            }

            $Status = if ($ExitCode -eq 0 -or $ExitCode -eq 3010) { 'SUCCESS' } else { 'FAILED' }
            @{ Status=$Status; ExitCode=$ExitCode; Message=if ($ExitCode -eq 3010) { 'Success - Reboot Required' } else { '' } }

        } -ArgumentList $InstallerPath, $InstallerArgs, $InstallerType, $AppName

        $Color = if ($Result.Status -in 'SUCCESS','ALREADY_INSTALLED') { 'Green' } else { 'Red' }
        Write-Host "    [$($Result.Status)] ExitCode: $($Result.ExitCode) $($Result.Message)" -ForegroundColor $Color

        $Results += [PSCustomObject]@{
            Computer  = $Computer
            AppName   = $AppName
            Status    = $Result.Status
            ExitCode  = $Result.ExitCode
            Message   = $Result.Message
            Timestamp = (Get-Date -f 'yyyy-MM-dd HH:mm:ss')
        }
    } catch {
        Write-Host "    [ERROR] $_" -ForegroundColor Red
        $Results += [PSCustomObject]@{ Computer=$Computer; AppName=$AppName; Status='ERROR'; ExitCode=-1; Message=$_.Exception.Message; Timestamp=(Get-Date -f 'yyyy-MM-dd HH:mm:ss') }
    }
}

$Results | Export-Csv $OutputPath -NoTypeInformation
$Success = ($Results | Where-Object Status -in 'SUCCESS','ALREADY_INSTALLED').Count
Write-Host "
Deployment complete: $Success/$($Computers.Count) successful | Log: $OutputPath" -ForegroundColor Green

# ============================================================
# BitLocker Compliance & Key Backup to AD
# ============================================================
$Computers  = @($env:COMPUTERNAME)
$OutputPath = "C:\Reports\BitLockerStatus_$(Get-Date -f 'yyyyMMdd').csv"
$Results    = @()

foreach ($Computer in $Computers) {
    Write-Host "Checking BitLocker on: $Computer" -ForegroundColor Cyan
    try {
        $Data = Invoke-Command -ComputerName $Computer -ScriptBlock {
            $Volumes = Get-BitLockerVolume -ErrorAction SilentlyContinue
            $Volumes | ForEach-Object {
                [PSCustomObject]@{
                    MountPoint      = $_.MountPoint
                    ProtectionStatus = $_.ProtectionStatus
                    EncryptionMethod = $_.EncryptionMethod
                    EncryptionPct   = $_.EncryptionPercentage
                    LockStatus      = $_.LockStatus
                    KeyProtectors   = ($_.KeyProtector | ForEach-Object { $_.KeyProtectorType }) -join ', '
                    HasRecoveryKey  = ($_.KeyProtector | Where-Object { $_.KeyProtectorType -eq 'RecoveryPassword' }).Count -gt 0
                }
            }
        }

        foreach ($Vol in $Data) {
            $Color = if ($Vol.ProtectionStatus -eq 'On') { 'Green' } else { 'Red' }
            Write-Host "  $($Vol.MountPoint): $($Vol.ProtectionStatus) ($($Vol.EncryptionPct)%)" -ForegroundColor $Color

            # Back up recovery key to AD
            if ($Vol.HasRecoveryKey) {
                try {
                    $BLV = Get-BitLockerVolume -MountPoint $Vol.MountPoint
                    $BLV.KeyProtector | Where-Object { $_.KeyProtectorType -eq 'RecoveryPassword' } | ForEach-Object {
                        Backup-BitLockerKeyProtector -MountPoint $Vol.MountPoint -KeyProtectorId $_.KeyProtectorId
                        Write-Host '    [OK] Recovery key backed up to AD' -ForegroundColor Green
                    }
                } catch { Write-Host '    [WARN] Could not back up key to AD' -ForegroundColor Yellow }
            }

            $Results += [PSCustomObject]@{
                Computer         = $Computer
                Drive            = $Vol.MountPoint
                Protected        = $Vol.ProtectionStatus
                Method           = $Vol.EncryptionMethod
                EncryptionPct    = $Vol.EncryptionPct
                HasRecoveryKey   = $Vol.HasRecoveryKey
                KeyTypes         = $Vol.KeyProtectors
            }
        }
    } catch {
        Write-Host "  [ERROR] $_" -ForegroundColor Red
    }
}

$Results | Export-Csv $OutputPath -NoTypeInformation
$Protected   = ($Results | Where-Object Protected -eq 'On').Count
$Unprotected = ($Results | Where-Object Protected -ne 'On').Count
Write-Host "
Protected: $Protected | Unprotected: $Unprotected | Report: $OutputPath" -ForegroundColor Yellow

# ============================================================
# Endpoint Hardware Inventory
# ============================================================
$Computers  = @($env:COMPUTERNAME)
$OutputPath = "C:\Reports\HardwareInventory_$(Get-Date -f 'yyyyMMdd').csv"
$Results    = @()

foreach ($Computer in $Computers) {
    Write-Host "Scanning: $Computer" -ForegroundColor Cyan
    try {
        $HW = Invoke-Command -ComputerName $Computer -ErrorAction Stop -ScriptBlock {
            $CS   = Get-CimInstance Win32_ComputerSystem
            $OS   = Get-CimInstance Win32_OperatingSystem
            $CPU  = Get-CimInstance Win32_Processor | Select-Object -First 1
            $BIOS = Get-CimInstance Win32_BIOS
            $Disks = Get-CimInstance Win32_DiskDrive | ForEach-Object { "$($_.Caption) ($([math]::Round($_.Size/1GB,0))GB)" }
            $GPU  = Get-CimInstance Win32_VideoController | ForEach-Object { $_.Caption }
            $RAM  = Get-CimInstance Win32_PhysicalMemory | ForEach-Object { "$($_.Manufacturer) $($_.Capacity/1GB)GB $($_.Speed)MHz" }
            $Net  = Get-CimInstance Win32_NetworkAdapter -Filter 'PhysicalAdapter=true' | ForEach-Object { $_.Name }
            $Mon  = Get-CimInstance Win32_DesktopMonitor | ForEach-Object { $_.Caption }

            [PSCustomObject]@{
                Hostname     = $env:COMPUTERNAME
                Manufacturer = $CS.Manufacturer
                Model        = $CS.Model
                Serial       = $BIOS.SerialNumber
                BIOSVersion  = $BIOS.SMBIOSBIOSVersion
                OS           = $OS.Caption
                OSBuild      = $OS.BuildNumber
                CPU          = $CPU.Name
                Cores        = $CPU.NumberOfCores
                Threads      = $CPU.NumberOfLogicalProcessors
                RAM_GB       = [math]::Round($CS.TotalPhysicalMemory/1GB,2)
                RAMModules   = $RAM -join ' | '
                Disks        = $Disks -join ' | '
                GPU          = $GPU -join ' | '
                NetworkCards = $Net -join ' | '
                Monitors     = $Mon -join ' | '
            }
        }
        $Results += $HW
        Write-Host "  [OK] $($HW.Manufacturer) $($HW.Model) | $($HW.CPU) | $($HW.RAM_GB)GB RAM" -ForegroundColor Green
    } catch {
        Write-Host "  [ERROR] $Computer - $_" -ForegroundColor Red
    }
}

$Results | Export-Csv $OutputPath -NoTypeInformation
Write-Host "
Inventory complete: $($Results.Count) computers | Report: $OutputPath" -ForegroundColor Green

# ============================================================
# Bulk Add Users to Microsoft Teams
# ============================================================
# CSV format: UPN, TeamName, Role (Member/Owner)
# ============================================================
Connect-MgGraph -Scopes 'TeamMember.ReadWrite.All','Group.ReadWrite.All' -NoWelcome

$CsvPath    = 'C:\Temp\TeamAssignments.csv'
$OutputPath = "C:\Logs\TeamBulkAdd_$(Get-Date -f 'yyyyMMdd_HHmm').csv"
$Results    = @()

$Assignments = Import-Csv $CsvPath
Write-Host "Processing $($Assignments.Count) team assignments..." -ForegroundColor Cyan

# Cache team lookup to avoid repeated API calls
$TeamCache = @{}
$Teams = Get-MgGroup -Filter "resourceProvisioningOptions/Any(x:x eq 'Team')" -All
$Teams | ForEach-Object { $TeamCache[$_.DisplayName] = $_.Id }

foreach ($Row in $Assignments) {
    $Status = ''
    $Error  = ''
    try {
        $TeamId = $TeamCache[$Row.TeamName]
        if (-not $TeamId) { throw "Team '$($Row.TeamName)' not found" }

        $User = Get-MgUser -UserId $Row.UPN -ErrorAction Stop
        $Role = if ($Row.Role -eq 'Owner') { 'owner' } else { 'member' }

        # Check if already a member
        $Existing = Get-MgTeamMember -TeamId $TeamId | Where-Object { $_.AdditionalProperties['userId'] -eq $User.Id }

        if ($Existing) {
            $Status = 'ALREADY_MEMBER'
        } else {
            $Params = @{
                '@odata.type' = '#microsoft.graph.aadUserConversationMember'
                Roles         = @($Role)
                'user@odata.bind' = "https://graph.microsoft.com/v1.0/users('$($User.Id)')"
            }
            New-MgTeamMember -TeamId $TeamId -BodyParameter $Params | Out-Null
            $Status = 'ADDED'
        }
        Write-Host "  [$Status] $($Row.UPN) -> $($Row.TeamName) ($Role)" -ForegroundColor Green
    } catch {
        $Status = 'ERROR'
        $Error  = $_.Exception.Message
        Write-Host "  [ERROR] $($Row.UPN) -> $($Row.TeamName): $Error" -ForegroundColor Red
    }

    $Results += [PSCustomObject]@{
        UPN      = $Row.UPN
        Team     = $Row.TeamName
        Role     = $Row.Role
        Status   = $Status
        Error    = $Error
        Time     = (Get-Date -f 'HH:mm:ss')
    }
}

$Results | Export-Csv $OutputPath -NoTypeInformation
$Added = ($Results | Where-Object Status -eq 'ADDED').Count
Write-Host "
Added: $Added | Already member: $(($Results|Where-Object Status -eq 'ALREADY_MEMBER').Count) | Errors: $(($Results|Where-Object Status -eq 'ERROR').Count)"
Write-Host "Log: $OutputPath" -ForegroundColor Green

# ============================================================
# Azure VM Power State Management
# ============================================================
Connect-AzAccount

$SubscriptionId = 'YOUR-SUBSCRIPTION-ID'
$Action         = 'Stop'   # Start | Stop | Deallocate | Restart
$FilterByTag    = $true
$TagName        = 'Environment'
$TagValue       = 'Dev'    # Only act on Dev VMs
$WhatIf         = $true    # Set $false to execute

Set-AzContext -SubscriptionId $SubscriptionId

# Get VMs
$VMs = if ($FilterByTag) {
    Get-AzVM | Where-Object { $_.Tags[$TagName] -eq $TagValue }
} else {
    Get-AzVM
}

Write-Host "Found $($VMs.Count) VMs matching criteria (Action=$Action, WhatIf=$WhatIf)" -ForegroundColor Cyan

foreach ($VM in $VMs) {
    $Status = (Get-AzVM -ResourceGroupName $VM.ResourceGroupName -Name $VM.Name -Status).Statuses | 
              Where-Object Code -like 'PowerState/*' | Select-Object -ExpandProperty DisplayStatus

    Write-Host "  $($VM.Name) [$($VM.ResourceGroupName)] - Current: $Status" -ForegroundColor Yellow

    if (-not $WhatIf) {
        switch ($Action) {
            'Start'       { Start-AzVM -ResourceGroupName $VM.ResourceGroupName -Name $VM.Name -NoWait }
            'Stop'        { Stop-AzVM  -ResourceGroupName $VM.ResourceGroupName -Name $VM.Name -Force -NoWait }
            'Deallocate'  { Stop-AzVM  -ResourceGroupName $VM.ResourceGroupName -Name $VM.Name -Force -NoWait }
            'Restart'     { Restart-AzVM -ResourceGroupName $VM.ResourceGroupName -Name $VM.Name -NoWait }
        }
        Write-Host "    [SENT] $Action command dispatched" -ForegroundColor Green
    } else {
        Write-Host "    [WHATIF] Would execute: $Action" -ForegroundColor Cyan
    }
}

if ($WhatIf) { Write-Host "
[NOTE] WhatIf mode. Set `$WhatIf=`$false to apply changes." -ForegroundColor Cyan }

# ============================================================
# Azure Cost & Budget Analysis
# ============================================================
Connect-AzAccount

$SubscriptionId = 'YOUR-SUBSCRIPTION-ID'
$OutputPath     = "C:\Reports\AzureCosts_$(Get-Date -f 'yyyyMMdd').csv"

Set-AzContext -SubscriptionId $SubscriptionId

# Date range (last 30 days)
$EndDate   = Get-Date -Format 'yyyy-MM-dd'
$StartDate = (Get-Date).AddDays(-30).ToString('yyyy-MM-dd')

Write-Host "Fetching cost data: $StartDate to $EndDate" -ForegroundColor Cyan

# Get cost by resource group
$CostParams = @{
    Scope       = "/subscriptions/$SubscriptionId"
    Timeframe   = 'Custom'
    TimePeriodFrom = $StartDate
    TimePeriodTo   = $EndDate
    DatasetGranularity = 'None'
    DatasetGrouping = @(
        @{ Type='Dimension'; Name='ResourceGroupName' },
        @{ Type='Dimension'; Name='ServiceName' }
    )
    DatasetAggregation = @{
        totalCost = @{ Name='PreTaxCost'; Function='Sum' }
    }
}

try {
    $CostData = Invoke-AzCostManagementQuery @CostParams

    $Report = $CostData.Row | ForEach-Object {
        [PSCustomObject]@{
            Cost            = [math]::Round($_[0], 2)
            Currency        = $_[1]
            ResourceGroup   = $_[2]
            ServiceName     = $_[3]
        }
    } | Sort-Object Cost -Descending

    $Report | Export-Csv $OutputPath -NoTypeInformation

    $TotalCost = [math]::Round(($Report | Measure-Object Cost -Sum).Sum, 2)
    Write-Host "
Total spend (30d): `$$TotalCost" -ForegroundColor Yellow
    Write-Host "
Top 10 by cost:" -ForegroundColor Cyan
    $Report | Select-Object -First 10 | ForEach-Object {
        Write-Host "  `$$($_.Cost) - $($_.ServiceName) [$($_.ResourceGroup)]"
    }
    Write-Host "
Report: $OutputPath" -ForegroundColor Green

} catch {
    Write-Host "[ERROR] $_" -ForegroundColor Red
    Write-Host 'Ensure you have Cost Management Reader role on the subscription.' -ForegroundColor Yellow
}

# ============================================================
# IIS Web Server Inventory
# ============================================================
# Requires: WebAdministration module (install IIS Management Tools)
# ============================================================

$Computers  = @($env:COMPUTERNAME)
$OutputPath = "C:\Reports\IISInventory_$(Get-Date -f 'yyyyMMdd').csv"
$Results    = @()

foreach ($Computer in $Computers) {
    Write-Host "Scanning IIS on: $Computer" -ForegroundColor Cyan
    try {
        $Data = Invoke-Command -ComputerName $Computer -ScriptBlock {
            Import-Module WebAdministration
            $Sites = Get-Website
            $Pools = Get-WebConfiguration -Filter 'system.applicationHost/applicationPools/add'

            $Sites | ForEach-Object {
                $Site = $_
                $Bindings = $Site.Bindings.Collection | ForEach-Object {
                    "$($_.Protocol)://$($_.BindingInformation)"
                }
                $Pool    = $Pools | Where-Object Name -eq $Site.ApplicationPool
                $AppPath = $Site.PhysicalPath

                [PSCustomObject]@{
                    SiteName          = $Site.Name
                    State             = $Site.State
                    PhysicalPath      = $AppPath
                    ApplicationPool   = $Site.ApplicationPool
                    PoolState         = $Pool.State
                    PoolIdentity      = $Pool.ProcessModel.UserName
                    PoolManagedRuntime = $Pool.ManagedRuntimeVersion
                    Bindings          = $Bindings -join ' | '
                    LogDirectory      = $Site.LogFile.Directory
                    LogEnabled        = $Site.LogFile.Enabled
                }
            }
        }
        foreach ($Site in $Data) {
            $Site | Add-Member -MemberType NoteProperty -Name 'Server' -Value $Computer
            $Results += $Site
        }
        Write-Host "  Found $($Data.Count) sites" -ForegroundColor Green
    } catch {
        Write-Host "  [ERROR] $_" -ForegroundColor Red
    }
}

$Results | Export-Csv $OutputPath -NoTypeInformation
Write-Host "
Total IIS sites: $($Results.Count) | Report: $OutputPath" -ForegroundColor Green

# ============================================================
# Scheduled Task Audit
# ============================================================
$Computers  = @($env:COMPUTERNAME)
$OutputPath = "C:\Reports\ScheduledTasks_$(Get-Date -f 'yyyyMMdd').csv"
$Results    = @()
$SkipPaths  = @('\Microsoft\', '\MicrosoftAntimalware\')

foreach ($Computer in $Computers) {
    Write-Host "Scanning tasks on: $Computer" -ForegroundColor Cyan
    try {
        $Tasks = Invoke-Command -ComputerName $Computer -ScriptBlock {
            param($Skip)
            Get-ScheduledTask | Where-Object {
                $TaskPath = $_.TaskPath
                -not ($Skip | Where-Object { $TaskPath -like "*$_*" })
            } | ForEach-Object {
                $Task = $_
                $Info = $Task | Get-ScheduledTaskInfo -ErrorAction SilentlyContinue
                [PSCustomObject]@{
                    TaskName      = $Task.TaskName
                    TaskPath      = $Task.TaskPath
                    State         = $Task.State
                    Author        = $Task.Author
                    RunAs         = $Task.Principal.UserId
                    RunLevel      = $Task.Principal.RunLevel
                    Description   = $Task.Description
                    Actions       = ($Task.Actions | ForEach-Object { "$($_.Execute) $($_.Arguments)" }) -join ' | '
                    Triggers      = ($Task.Triggers | ForEach-Object { $_.CimClass.CimClassName }) -join '; '
                    LastRunTime   = $Info.LastRunTime
                    LastResult    = $Info.LastTaskResult
                    NextRunTime   = $Info.NextRunTime
                    LastResultHex = '0x{0:X8}' -f $Info.LastTaskResult
                }
            }
        } -ArgumentList (,$SkipPaths)

        foreach ($Task in $Tasks) {
            $Task | Add-Member -NotePropertyName 'Computer' -NotePropertyValue $Computer
            $Results += $Task
        }
        $Failed = ($Tasks | Where-Object { $_.LastResult -ne 0 -and $_.LastResult -ne $null }).Count
        Write-Host "  Tasks: $($Tasks.Count) | Failed last run: $Failed" -ForegroundColor $(if ($Failed -gt 0) {'Yellow'} else {'Green'})
    } catch {
        Write-Host "  [ERROR] $_" -ForegroundColor Red
    }
}

$Results | Export-Csv $OutputPath -NoTypeInformation
Write-Host "
Total tasks: $($Results.Count) | Report: $OutputPath" -ForegroundColor Green

# ============================================================
# PowerShell Remoting Setup & Connectivity Test
# ============================================================
$Computers  = @('SERVER01', 'SERVER02', 'PC01')
$OutputPath = "C:\Reports\PSRemoting_$(Get-Date -f 'yyyyMMdd').csv"
$Results    = @()

# Function to test PS Remoting
function Test-PSRemoting ($Computer) {
    $Result = [PSCustomObject]@{
        Computer      = $Computer
        Ping          = $false
        WinRM         = $false
        PSSession     = $false
        InvokeCommand = $false
        Hostname      = ''
        PSVersion     = ''
        Error         = ''
    }

    # Test 1: Ping
    $Result.Ping = (Test-Connection -ComputerName $Computer -Count 1 -Quiet)
    if (-not $Result.Ping) {
        $Result.Error = 'Unreachable (ping failed)'
        return $Result
    }

    # Test 2: WinRM port
    $WinRM = Test-NetConnection -ComputerName $Computer -Port 5985 -WarningAction SilentlyContinue
    $Result.WinRM = $WinRM.TcpTestSucceeded
    if (-not $Result.WinRM) {
        $Result.Error = 'WinRM port 5985 closed'
        return $Result
    }

    # Test 3: PSSession
    try {
        $Session = New-PSSession -ComputerName $Computer -ErrorAction Stop
        $Result.PSSession = $true

        # Test 4: Invoke-Command
        $Info = Invoke-Command -Session $Session -ScriptBlock {
            [PSCustomObject]@{
                Hostname  = $env:COMPUTERNAME
                PSVersion = $PSVersionTable.PSVersion.ToString()
            }
        }
        $Result.InvokeCommand = $true
        $Result.Hostname  = $Info.Hostname
        $Result.PSVersion = $Info.PSVersion
        Remove-PSSession $Session
    } catch {
        $Result.Error = $_.Exception.Message
    }
    return $Result
}

# Enable WinRM on local machine if needed
Write-Host 'Checking local WinRM status...' -ForegroundColor Cyan
$WinRMStatus = Get-Service WinRM
if ($WinRMStatus.Status -ne 'Running') {
    Write-Host '  Starting WinRM service...' -ForegroundColor Yellow
    Enable-PSRemoting -Force -SkipNetworkProfileCheck
}

Write-Host 'Testing PS Remoting connectivity...' -ForegroundColor Cyan
Write-Host ('{0,-20} {1,-6} {2,-6} {3,-10} {4,-8} {5}' -f 'Computer','Ping','WinRM','Session','Invoke','PSVersion')
Write-Host ('-' * 70)

foreach ($Computer in $Computers) {
    $R = Test-PSRemoting $Computer
    $Results += $R
    $Color = if ($R.InvokeCommand) { 'Green' } elseif ($R.Ping) { 'Yellow' } else { 'Red' }
    Write-Host ('{0,-20} {1,-6} {2,-6} {3,-10} {4,-8} {5}' -f $R.Computer, $R.Ping, $R.WinRM, $R.PSSession, $R.InvokeCommand, $R.PSVersion) -ForegroundColor $Color
    if ($R.Error) { Write-Host "  Error: $($R.Error)" -ForegroundColor Red }
}

$Results | Export-Csv $OutputPath -NoTypeInformation
$OK = ($Results | Where-Object InvokeCommand).Count
Write-Host "
Reachable via PS Remoting: $OK/$($Computers.Count) | Report: $OutputPath" -ForegroundColor Yellow

# ============================================================
# Certificate Expiration Monitor
# ============================================================
$Computers       = @($env:COMPUTERNAME)
$WebEndpoints    = @('https://contoso.com','https://portal.contoso.com','https://mail.contoso.com')
$WarningDays     = 60
$CriticalDays    = 30
$OutputPath      = "C:\Reports\CertExpiry_$(Get-Date -f 'yyyyMMdd').csv"
$Results         = @()

# --- Scan Windows Certificate Stores ---
foreach ($Computer in $Computers) {
    Write-Host "Scanning cert stores on: $Computer" -ForegroundColor Cyan
    $Stores = @('Cert:\LocalMachine\My', 'Cert:\LocalMachine\WebHosting')
    try {
        $Certs = Invoke-Command -ComputerName $Computer -ScriptBlock {
            param($Stores)
            foreach ($Store in $Stores) {
                Get-ChildItem $Store -ErrorAction SilentlyContinue | ForEach-Object {
                    [PSCustomObject]@{
                        Store     = $Store
                        Subject   = $_.Subject
                        Issuer    = $_.Issuer
                        Thumbprint = $_.Thumbprint
                        NotBefore = $_.NotBefore
                        NotAfter  = $_.NotAfter
                        DaysLeft  = [math]::Round(($_.NotAfter - (Get-Date)).TotalDays)
                        HasPrivKey = $_.HasPrivateKey
                        DNSNames   = ($_.DnsNameList.Unicode) -join '; '
                    }
                }
            }
        } -ArgumentList (,$Stores)

        foreach ($Cert in $Certs) {
            $Status = if ($Cert.DaysLeft -lt 0) { 'EXPIRED' }
                      elseif ($Cert.DaysLeft -le $CriticalDays) { 'CRITICAL' }
                      elseif ($Cert.DaysLeft -le $WarningDays) { 'WARNING' }
                      else { 'OK' }
            $Color  = switch ($Status) { 'EXPIRED' {'Red'} 'CRITICAL' {'Red'} 'WARNING' {'Yellow'} default {'Green'} }
            if ($Status -ne 'OK') {
                Write-Host "  [$Status] $($Cert.Subject) - $($Cert.DaysLeft) days" -ForegroundColor $Color
            }
            $Results += $Cert | Add-Member -NotePropertyName Computer -NotePropertyValue $Computer -PassThru |
                               Add-Member -NotePropertyName Status -NotePropertyValue $Status -PassThru |
                               Add-Member -NotePropertyName Source -NotePropertyValue 'CertStore' -PassThru
        }
    } catch { Write-Host "  [ERROR] $_" -ForegroundColor Red }
}

# --- Scan HTTPS Endpoints ---
Write-Host "
Checking HTTPS endpoints..." -ForegroundColor Cyan
foreach ($URL in $WebEndpoints) {
    try {
        $Request = [System.Net.HttpWebRequest]::Create($URL)
        $Request.AllowAutoRedirect = $false
        $Request.Timeout = 5000
        $Response = $Request.GetResponse()
        $Cert     = $Request.ServicePoint.Certificate
        $Expiry   = [DateTime]::ParseExact($Cert.GetExpirationDateString(), 'ddd MMM dd HH:mm:ss yyyy', [System.Globalization.CultureInfo]::InvariantCulture)
        $DaysLeft = [math]::Round(($Expiry - (Get-Date)).TotalDays)
        $Status   = if ($DaysLeft -le $CriticalDays) {'CRITICAL'} elseif ($DaysLeft -le $WarningDays) {'WARNING'} else {'OK'}
        $Color    = if ($Status -ne 'OK') {'Red'} else {'Green'}
        Write-Host "  $URL - $DaysLeft days [$Status]" -ForegroundColor $Color
        $Results += [PSCustomObject]@{ Computer=$URL; Source='HTTPS'; Subject=$Cert.Subject; NotAfter=$Expiry; DaysLeft=$DaysLeft; Status=$Status }
        $Response.Close()
    } catch { Write-Host "  [ERROR] $URL - $_" -ForegroundColor Red }
}

$Results | Export-Csv $OutputPath -NoTypeInformation
$Critical = ($Results | Where-Object Status -in 'CRITICAL','EXPIRED').Count
Write-Host "
Certificates checked: $($Results.Count) | Critical/Expired: $Critical | Report: $OutputPath" -ForegroundColor $(if ($Critical -gt 0) {'Red'} else {'Green'})

# ============================================================
# File Server Storage Analytics
# ============================================================
$SharePaths  = @('\\FILESERVER\Data','\\FILESERVER\Departments')
$OutputPath  = "C:\Reports\StorageAnalytics_$(Get-Date -f 'yyyyMMdd').csv"
$TopNLargest = 50
$Results     = @()

foreach ($Share in $SharePaths) {
    Write-Host "Analyzing: $Share" -ForegroundColor Cyan
    try {
        $Files = Get-ChildItem -Path $Share -Recurse -File -ErrorAction SilentlyContinue
        Write-Host "  Files found: $($Files.Count)" -ForegroundColor Yellow

        # Extension breakdown
        $ExtStats = $Files | Group-Object Extension | ForEach-Object {
            [PSCustomObject]@{
                Share     = $Share
                Category  = 'ExtensionBreakdown'
                Key       = $_.Name
                FileCount = $_.Count
                TotalSizeMB = [math]::Round(($_.Group | Measure-Object Length -Sum).Sum/1MB, 2)
            }
        } | Sort-Object TotalSizeMB -Descending

        # Age analysis
        $Now = Get-Date
        $OldFiles = $Files | Where-Object { ($Now - $_.LastWriteTime).Days -gt 365 }

        # Largest files
        $Largest = $Files | Sort-Object Length -Descending | Select-Object -First $TopNLargest

        # Summary
        $TotalSizeGB = [math]::Round(($Files | Measure-Object Length -Sum).Sum/1GB, 2)
        $OldSizeGB   = [math]::Round(($OldFiles | Measure-Object Length -Sum).Sum/1GB, 2)

        Write-Host "  Total: ${TotalSizeGB}GB | Files over 1yr old: $($OldFiles.Count) ($OldSizeGB GB)" -ForegroundColor Green

        $Results += $ExtStats
        $Results += $Largest | ForEach-Object {
            [PSCustomObject]@{
                Share     = $Share
                Category  = 'LargestFiles'
                Key       = $_.FullName
                FileCount = 1
                TotalSizeMB = [math]::Round($_.Length/1MB, 2)
            }
        }
    } catch {
        Write-Host "  [ERROR] $_" -ForegroundColor Red
    }
}

$Results | Export-Csv $OutputPath -NoTypeInformation
Write-Host "
Analytics complete | Report: $OutputPath" -ForegroundColor Green

# ============================================================
# Azure OpenAI Service Inventory & Usage
# ============================================================
Connect-AzAccount

$OutputPath = "C:\Reports\AzureOpenAI_$(Get-Date -f 'yyyyMMdd').csv"
$Results    = @()

$Subscriptions = Get-AzSubscription
Write-Host "Scanning $($Subscriptions.Count) subscriptions for Azure OpenAI..." -ForegroundColor Cyan

foreach ($Sub in $Subscriptions) {
    Set-AzContext -SubscriptionId $Sub.Id | Out-Null

    # Get all Azure OpenAI accounts
    $AIAccounts = Get-AzResource -ResourceType 'Microsoft.CognitiveServices/accounts' | 
                  Where-Object { $_.Kind -eq 'OpenAI' }

    if ($AIAccounts.Count -eq 0) { continue }
    Write-Host "  [$($Sub.Name)] Found $($AIAccounts.Count) Azure OpenAI accounts" -ForegroundColor Yellow

    foreach ($Account in $AIAccounts) {
        try {
            $Details = Get-AzCognitiveServicesAccount `
                -ResourceGroupName $Account.ResourceGroupName `
                -Name $Account.Name

            # Get deployments via REST API
            $Token = (Get-AzAccessToken -ResourceUrl 'https://management.azure.com/').Token
            $DeployURI = "https://management.azure.com$($Account.ResourceId)/deployments?api-version=2023-05-01"
            $DeployResp = Invoke-RestMethod -Uri $DeployURI -Headers @{Authorization="Bearer $Token"}

            if ($DeployResp.value.Count -eq 0) {
                $Results += [PSCustomObject]@{
                    Subscription    = $Sub.Name
                    ResourceGroup   = $Account.ResourceGroupName
                    AccountName     = $Account.Name
                    Location        = $Details.Location
                    SKU             = $Details.Sku.Name
                    Endpoint        = $Details.Properties.Endpoint
                    PublicAccess    = $Details.Properties.PublicNetworkAccess
                    DeploymentName  = 'No deployments'
                    ModelName       = ''
                    ModelVersion    = ''
                    Capacity        = 0
                    ProvisionState  = $Details.Properties.ProvisioningState
                }
            } else {
                foreach ($Deploy in $DeployResp.value) {
                    $Results += [PSCustomObject]@{
                        Subscription    = $Sub.Name
                        ResourceGroup   = $Account.ResourceGroupName
                        AccountName     = $Account.Name
                        Location        = $Details.Location
                        SKU             = $Details.Sku.Name
                        Endpoint        = $Details.Properties.Endpoint
                        PublicAccess    = $Details.Properties.PublicNetworkAccess
                        DeploymentName  = $Deploy.name
                        ModelName       = $Deploy.properties.model.name
                        ModelVersion    = $Deploy.properties.model.version
                        Capacity        = $Deploy.sku.capacity
                        ProvisionState  = $Deploy.properties.provisioningState
                    }
                    Write-Host "    $($Account.Name) / $($Deploy.name) - $($Deploy.properties.model.name) @ $($Deploy.sku.capacity)K TPM" -ForegroundColor Green
                }
            }
        } catch {
            Write-Host "    [ERROR] $($Account.Name): $_" -ForegroundColor Red
        }
    }
}

$Results | Export-Csv $OutputPath -NoTypeInformation
Write-Host "
Total AI deployments: $($Results.Count) | Report: $OutputPath" -ForegroundColor Green

# ============================================================
# Azure Machine Learning Workspace Inventory
# ============================================================
Connect-AzAccount

$SubscriptionId = 'YOUR-SUBSCRIPTION-ID'
$OutputPath     = "C:\Reports\AzureML_Inventory_$(Get-Date -f 'yyyyMMdd').csv"
Set-AzContext -SubscriptionId $SubscriptionId

Write-Host 'Scanning Azure ML workspaces...' -ForegroundColor Cyan

$Workspaces = Get-AzResource -ResourceType 'Microsoft.MachineLearningServices/workspaces'
Write-Host "Found $($Workspaces.Count) ML workspaces" -ForegroundColor Yellow

$Results    = @()
$Token      = (Get-AzAccessToken).Token
$Headers    = @{ Authorization = "Bearer $Token"; 'Content-Type' = 'application/json' }
$APIVersion = '2023-04-01'

foreach ($WS in $Workspaces) {
    Write-Host "  Workspace: $($WS.Name)" -ForegroundColor Cyan
    $BaseURI = "https://management.azure.com$($WS.ResourceId)"

    # Compute clusters
    try {
        $Computes   = Invoke-RestMethod -Uri "$BaseURI/computes?api-version=$APIVersion" -Headers $Headers
        $ComputeList = $Computes.value | ForEach-Object { "$($_.name)($($_.properties.computeType))" }
    } catch { $ComputeList = @('Error') }

    # Online endpoints
    try {
        $Endpoints  = Invoke-RestMethod -Uri "$BaseURI/onlineEndpoints?api-version=$APIVersion" -Headers $Headers
        $EndpointList = $Endpoints.value | ForEach-Object { $_.name }
    } catch { $EndpointList = @('Error') }

    # Models
    try {
        $Models     = Invoke-RestMethod -Uri "$BaseURI/models?api-version=$APIVersion" -Headers $Headers
        $ModelList  = $Models.value | Select-Object -First 10 | ForEach-Object { $_.name }
    } catch { $ModelList = @('Error') }

    $Results += [PSCustomObject]@{
        WorkspaceName   = $WS.Name
        ResourceGroup   = $WS.ResourceGroupName
        Location        = $WS.Location
        SKU             = $WS.Sku.Name
        ComputeCount    = $Computes.value.Count
        Computes        = $ComputeList -join '; '
        EndpointCount   = $Endpoints.value.Count
        Endpoints       = $EndpointList -join '; '
        ModelCount      = $Models.value.Count
        RecentModels    = $ModelList -join '; '
        Tags            = ($WS.Tags.GetEnumerator() | ForEach-Object { "$($_.Key)=$($_.Value)" }) -join '; '
    }

    Write-Host "    Compute: $($Computes.value.Count) | Endpoints: $($Endpoints.value.Count) | Models: $($Models.value.Count)" -ForegroundColor Green
}

$Results | Export-Csv $OutputPath -NoTypeInformation
Write-Host "
ML workspaces inventoried: $($Results.Count) | Report: $OutputPath" -ForegroundColor Green

# ============================================================
# AI Governance & Responsible AI Audit
# ============================================================
Connect-AzAccount

$SubscriptionId = 'YOUR-SUBSCRIPTION-ID'
$OutputPath     = "C:\Reports\AIGovernance_$(Get-Date -f 'yyyyMMdd').html"
$RequiredTags   = @('Owner', 'CostCenter', 'Environment', 'DataClassification')
$Results        = @()
Set-AzContext -SubscriptionId $SubscriptionId

Write-Host 'AI Governance Audit' -ForegroundColor Cyan

# Get all AI-related resources
$AITypes = @(
    'Microsoft.CognitiveServices/accounts',
    'Microsoft.MachineLearningServices/workspaces',
    'Microsoft.BotService/botServices'
)

$AllAIResources = foreach ($Type in $AITypes) {
    Get-AzResource -ResourceType $Type -ErrorAction SilentlyContinue
}

Write-Host "Total AI resources: $($AllAIResources.Count)" -ForegroundColor Yellow

foreach ($Resource in $AllAIResources) {
    $Flags = @()

    # Check required tags
    $MissingTags = $RequiredTags | Where-Object { -not $Resource.Tags[$_] }
    if ($MissingTags) { $Flags += "MISSING_TAGS:$($MissingTags -join ',')"
    }

    # Check managed identity
    if ($Resource.Identity.Type -eq 'None' -or -not $Resource.Identity) {
        $Flags += 'NO_MANAGED_IDENTITY'
    }

    # Check for Cognitive Services specifics
    if ($Resource.ResourceType -eq 'Microsoft.CognitiveServices/accounts') {
        try {
            $Details = Get-AzCognitiveServicesAccount -ResourceGroupName $Resource.ResourceGroupName -Name $Resource.Name
            if ($Details.Properties.PublicNetworkAccess -eq 'Enabled') { $Flags += 'PUBLIC_NETWORK_ACCESS' }
            if (-not $Details.Properties.Encryption.KeySource) { $Flags += 'NO_CMK_ENCRYPTION' }
        } catch {}
    }

    # Check diagnostic settings
    try {
        $Diag = Get-AzDiagnosticSetting -ResourceId $Resource.ResourceId -ErrorAction SilentlyContinue
        if (-not $Diag) { $Flags += 'NO_DIAGNOSTICS' }
    } catch { $Flags += 'NO_DIAGNOSTICS' }

    $RiskLevel = if ($Flags.Count -ge 3) { 'HIGH' } elseif ($Flags.Count -ge 1) { 'MEDIUM' } else { 'LOW' }
    $Color     = switch ($RiskLevel) { 'HIGH' {'Red'} 'MEDIUM' {'Yellow'} default {'Green'} }
    Write-Host "  [$RiskLevel] $($Resource.Name) ($($Resource.ResourceType.Split('/')[-1])): $($Flags -join ', ')" -ForegroundColor $Color

    $Results += [PSCustomObject]@{
        ResourceName    = $Resource.Name
        ResourceType    = $Resource.ResourceType
        ResourceGroup   = $Resource.ResourceGroupName
        Location        = $Resource.Location
        RiskLevel       = $RiskLevel
        FlagCount       = $Flags.Count
        Flags           = $Flags -join '; '
        HasRequiredTags = $MissingTags.Count -eq 0
        MissingTags     = $MissingTags -join ', '
        Tags            = ($Resource.Tags.GetEnumerator() | ForEach-Object { "$($_.Key)=$($_.Value)" }) -join '; '
    }
}

# Generate HTML Report
$Rows = $Results | ForEach-Object {
    $BgColor = switch ($_.RiskLevel) { 'HIGH' {'#ff5252'} 'MEDIUM' {'#ff9800'} default {'#4caf50'} }
    "<tr><td>$($_.ResourceName)</td><td>$($_.ResourceType.Split('/')[-1])</td><td>$($_.ResourceGroup)</td><td style='color:$BgColor;font-weight:bold'>$($_.RiskLevel)</td><td>$($_.Flags)</td></tr>"
} | Out-String

$High   = ($Results | Where-Object RiskLevel -eq 'HIGH').Count
$Medium = ($Results | Where-Object RiskLevel -eq 'MEDIUM').Count
$Low    = ($Results | Where-Object RiskLevel -eq 'LOW').Count

$HTML = "<!DOCTYPE html><html><head><title>AI Governance Audit</title><style>body{font-family:Segoe UI;margin:40px;background:#1e1e2e;color:#fff;} h1{color:#4FC3F7;} table{border-collapse:collapse;width:100%;margin-top:20px;} th{background:#0078D4;color:white;padding:10px;} td{border:1px solid #444;padding:9px;} .stats{display:flex;gap:20px;margin:20px 0;} .stat{background:#2a2a3e;padding:20px;border-radius:8px;text-align:center;flex:1;} .num{font-size:40px;font-weight:bold;}</style></head><body><h1>AI Governance & Responsible AI Audit</h1><p>Subscription: $SubscriptionId | Generated: $(Get-Date -f 'yyyy-MM-dd HH:mm')</p><div class='stats'><div class='stat'><div class='num' style='color:#f44336'>$High</div><div>HIGH RISK</div></div><div class='stat'><div class='num' style='color:#ff9800'>$Medium</div><div>MEDIUM RISK</div></div><div class='stat'><div class='num' style='color:#4caf50'>$Low</div><div>LOW RISK</div></div><div class='stat'><div class='num'>$($Results.Count)</div><div>TOTAL RESOURCES</div></div></div><table><tr><th>Resource</th><th>Type</th><th>Resource Group</th><th>Risk</th><th>Findings</th></tr>$Rows</table></body></html>"

$HTML | Out-File $OutputPath -Encoding UTF8
Write-Host "
High: $High | Medium: $Medium | Low: $Low"
Write-Host "HTML Report: $OutputPath" -ForegroundColor Green
Start-Process $OutputPath
